const fs = require('fs'), path = require('path');
const REPO = 'c:\\horaizon-3.0';
const ACTIVE = path.join(REPO, '_architecture', 'tasks', 'active');
const PROPOSED = path.join(REPO, '_architecture', 'tasks', 'proposed');
const raw = $input.first().json.text || '';
const topicKey = $('Loop Over Topics').item.json.topicKey;
const allFiles = [...fs.readdirSync(ACTIVE), ...(fs.existsSync(PROPOSED) ? fs.readdirSync(PROPOSED) : [])];
const nums = allFiles.map(f => { const m = f.match(/TASK-(\d+)/); return m ? parseInt(m[1]) : 0; }).filter(n => n > 0);
let nextNum = (nums.length ? Math.max(...nums) : 15) + 1;
const blocks = raw.split('---START_TASK---');
const written = [];
for (const block of blocks) {
  if (!block.includes('---END_TASK---')) continue;
  const taskMd = block.split('---END_TASK---')[0].trim();
  const titleLine = taskMd.split('\n').find(l => l.startsWith('# TASK-')) || '';
  let slug = topicKey;
  if (titleLine.includes('\u2014')) slug = titleLine.split('\u2014')[1].trim().toLowerCase().replace(/\s+/g,'_').replace(/[^a-z0-9_]/g,'');
  const taskId = `TASK-${String(nextNum).padStart(3,'0')}`; nextNum++;
  const filename = `${taskId}_${slug}.md`;
  fs.mkdirSync(PROPOSED, { recursive: true });
  fs.writeFileSync(path.join(PROPOSED, filename), taskMd, 'utf8');
  written.push({ filename, taskMd, taskId });
}
return written.length > 0 ? written.map(t => ({ json: { filename: t.filename, task_markdown: t.taskMd, taskId: t.taskId } })) : [{ json: { filename: null, task_markdown: raw.slice(0,500), taskId: null, error: 'No task blocks found' } }];

