  const content = fs.readFileSync(path.join(ACTIVE, filename), 'utf8');
  const taskId = filename.split('_')[0];
  const MANUAL = new Set(['TASK-001','TASK-007']);
  const isDone = content.includes('[x] Done');
  return { json: { filename, taskId, content, skip: MANUAL.has(taskId) || isDone } };
});

